namespace sv_4b33d3bf043b4d68b2bac34c92ef3377.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors = ["Dr. Smith", "Dr. Johnson", "Dr. Williams", "Dr. Brown"];

    private static readonly Dictionary<string, List<string>> DoctorSlots = new()
    {
        ["Dr. Smith"] = ["9:00 AM", "10:00 AM", "11:00 AM", "2:00 PM", "3:00 PM"],
        ["Dr. Johnson"] = ["8:00 AM", "10:00 AM", "1:00 PM", "4:00 PM"],
        ["Dr. Williams"] = ["9:00 AM", "10:30 AM", "11:30 AM", "2:30 PM"],
        ["Dr. Brown"] = ["8:30 AM", "10:00 AM", "12:00 PM", "3:30 PM"]
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableSlotsAsync(string doctor, DateOnly date)
    {
        if (DoctorSlots.TryGetValue(doctor, out var slots))
        {
            return Task.FromResult(slots);
        }

        return Task.FromResult(new List<string>());
    }

    public Task<ValidationResult> ValidatePatientAsync(string email, string insuranceProvider, string doctor, string timeSlot)
    {
        var result = new ValidationResult();

        // Reject patients with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.FieldErrors["Email"] = "Account has outstanding balance";
        }

        // Reject self-pay patients for doctors that don't accept them
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            result.FieldErrors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        // Simulate race condition on time slot
        if (timeSlot == "10:00 AM")
        {
            result.FieldErrors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(result);
    }
}

public class ValidationResult
{
    public Dictionary<string, string> FieldErrors { get; set; } = new();
    public bool IsValid => FieldErrors.Count == 0;
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_4b33d3bf043b4d68b2bac34c92ef3377.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* STEP 1: Patient Information *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label for="patientName" class="form-label">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (serverErrors.ContainsKey("Email"))
            {
                <div class="validation-message">@serverErrors["Email"]</div>
            }
        </div>

        <div class="mb-3">
            <label for="phone" class="form-label">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label for="insurance" class="form-label">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select Insurance --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>
    </fieldset>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">Next</button>
    }

    @* STEP 2: Appointment Details *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label for="doctor" class="form-label">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor" @bind-Value:after="OnDoctorChanged">
                    <option value="">-- Select Doctor --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
                @if (serverErrors.ContainsKey("Doctor"))
                {
                    <div class="validation-message">@serverErrors["Doctor"]</div>
                }
            </div>

            <div class="mb-3">
                <label for="date" class="form-label">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate" @bind-Value:after="OnDateChanged" />
                <ValidationMessage For="() => Model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label for="timeSlot" class="form-label">Time Slot</label>
                <InputSelect id="timeSlot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select Time Slot --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (serverErrors.ContainsKey("TimeSlot"))
                {
                    <div class="validation-message">@serverErrors["TimeSlot"]</div>
                }
            </div>

            <div class="mb-3">
                <label for="reason" class="form-label">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" @bind-Value="Model.ReasonForVisit" rows="3" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="BackToStep1">Back</button>
            <button type="button" class="btn btn-primary" @onclick="CheckAvailability">Check Availability</button>
        </fieldset>
    }

    @if (isConfirmed)
    {
        <div class="alert alert-success mt-3">
            <strong>Appointment confirmed!</strong> We'll send a confirmation to @Model.Email.
        </div>
    }
</EditForm>

@code {
    private AppointmentModel Model { get; set; } = new();
    private bool showStep2;
    private bool isConfirmed;
    private List<string> doctors = [];
    private List<string> availableSlots = [];
    private Dictionary<string, string> serverErrors = new();
    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(Model);
        var validationMessages = new ValidationMessageStore(editContext);

        bool isValid = true;

        if (string.IsNullOrWhiteSpace(Model.PatientName))
        {
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Email) || !Model.Email.Contains('@'))
        {
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        {
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            isValid = false;
        }

        if (isValid)
        {
            showStep2 = true;
            serverErrors.Clear();
        }
    }

    private async Task OnDoctorChanged()
    {
        serverErrors.Remove("Doctor");
        await LoadSlots();
    }

    private async Task OnDateChanged()
    {
        await LoadSlots();
    }

    private async Task LoadSlots()
    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(
                Model.Doctor, DateOnly.FromDateTime(Model.AppointmentDate.Value));
        }
        else
        {
            availableSlots = [];
        }

        Model.TimeSlot = string.Empty;
        serverErrors.Remove("TimeSlot");
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();

        // Client-side validation for step 2 fields
        bool isValid = true;

        if (string.IsNullOrWhiteSpace(Model.Doctor))
            isValid = false;
        if (!Model.AppointmentDate.HasValue || Model.AppointmentDate.Value.Date <= DateTime.Today)
            isValid = false;
        if (string.IsNullOrWhiteSpace(Model.TimeSlot))
            isValid = false;
        if (string.IsNullOrWhiteSpace(Model.ReasonForVisit))
            isValid = false;
        if (Model.ReasonForVisit?.Length > 500)
            isValid = false;

        if (!isValid)
            return;

        var result = await AppointmentService.ValidatePatientAsync(
            Model.Email, Model.InsuranceProvider, Model.Doctor, Model.TimeSlot);

        if (result.IsValid)
        {
            isConfirmed = true;
        }
        else
        {
            serverErrors = new Dictionary<string, string>(result.FieldErrors);
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        serverErrors.Clear();
    }

    private void HandleSubmit()
    {
        // Form submitted via enter key - route through check availability
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_4b33d3bf043b4d68b2bac34c92ef3377.Components.Pages;

public class AppointmentModel
{
    [Required(ErrorMessage = "Patient name is required")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required")]
    [EmailAddress(ErrorMessage = "Invalid email format")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone is required")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance provider is required")]
    public string InsuranceProvider { get; set; } = string.Empty;

    [Required(ErrorMessage = "Doctor is required")]
    public string Doctor { get; set; } = string.Empty;

    [Required(ErrorMessage = "Date is required")]
    [FutureDate(ErrorMessage = "Date must be in the future")]
    public DateTime? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Time slot is required")]
    public string TimeSlot { get; set; } = string.Empty;

    [Required(ErrorMessage = "Reason for visit is required")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters")]
    public string ReasonForVisit { get; set; } = string.Empty;
}

public class FutureDateAttribute : ValidationAttribute
{
    public override bool IsValid(object? value)
    {
        if (value is DateTime date)
        {
            return date.Date > DateTime.Today;
        }
        return false;
    }
}

